noncompliant:
// Noncompliant: Using #import directive
#import <stdio.h>
#import "myheader.h"

int main() {
    printf("Hello World");
    return 0;
}

compliant:
// Compliant: Using standard #include directive
#include <stdio.h>
#include "myheader.h"

int main() {
    printf("Hello World");
    return 0;
}
